class Solution:
    def minMovesToCaptureTheQueen(self, a, b, c, d, e, f):
        # Check if rook attacks queen directly (no bishop in between)
        def between(x, lo, hi):
            return lo < x < hi or hi < x < lo
        # Rook same row
        if a == e:
            if c != a or not between(d, b, f):
                return 1
        # Rook same column
        if b == f:
            if d != b or not between(c, a, e):
                return 1
        # Bishop same diagonal
        if abs(c - e) == abs(d - f):
            # Check if rook is between bishop and queen on diagonal
            if not (c + d == a + b and between(a, c, e)) and not (c - d == a - b and between(a, c, e)):
                # More precise check
                dc = 1 if e > c else -1
                dr = 1 if f > d else -1
                blocked = False
                x, y = c + dc, d + dr
                while (x, y) != (e, f):
                    if (x, y) == (a, b):
                        blocked = True
                        break
                    x += dc
                    y += dr
                if not blocked:
                    return 1
        return 2

