        # Rook same row as queen
        if a == e:
            # bishop blocks if it's on same row between them
            if not (c == a and min(b, f) < d < max(b, f)):
                return 1
        # Rook same column as queen
        if b == f:
            if not (d == b and min(a, e) < c < max(a, e)):
                return 1
        # Bishop on same diagonal as queen
        if abs(c - e) == abs(d - f):
            # check rook lies on that diagonal path
            dc = 1 if e > c else -1
            dr = 1 if f > d else -1
            # rook blocks if a,b is strictly between c,d and e,f on the diagonal
            if not (abs(a - c) == abs(b - d) and
                    min(c, e) < a < max(c, e) and
                    min(d, f) < b < max(d, f)):
                return 1
        return 2

